namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Fresh mozzarella, San Marzano tomatoes, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Add torn mozzarella pieces.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Cumin, Tomato sauce, Heavy cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Stir in cream and cooked chicken.\n6. Serve over basmati rice.", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco seasoning, Corn tortillas, Lettuce, Tomato, Cheddar cheese, Sour cream, Salsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 min.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with meat and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Green onions, Peanuts, Tamarind paste, Fish sauce, Sugar, Lime", Steps = "1. Soak rice noodles in warm water 30 min.\n2. Stir-fry shrimp until pink, set aside.\n3. Scramble eggs in the wok.\n4. Add drained noodles and sauce (tamarind, fish sauce, sugar).\n5. Toss with shrimp, bean sprouts, and green onions.\n6. Serve with crushed peanuts and lime wedge.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract", Steps = "1. Preheat oven to 425°F.\n2. Melt chocolate and butter together.\n3. Whisk eggs, sugar, and vanilla.\n4. Fold chocolate mixture into eggs, add flour.\n5. Pour into greased ramekins.\n6. Bake 12-14 minutes (center should be soft).\n7. Invert onto plates and serve immediately.", AverageRating = 4.9, RatingCount = 25 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan cheese, Croutons, Caesar dressing, Lemon juice, Anchovy paste, Garlic", Steps = "1. Wash and chop romaine lettuce.\n2. Make dressing: whisk anchovy paste, garlic, lemon juice, and olive oil.\n3. Toss lettuce with dressing.\n4. Top with shaved parmesan and croutons.\n5. Season with black pepper.", AverageRating = 4.0, RatingCount = 6 },
    };

    private readonly Dictionary<int, List<int>> _ratings = new();

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe == null) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();

        _ratings[recipeId].Add(stars);
        recipe.RatingCount = _ratings[recipeId].Count;
        recipe.AverageRating = Math.Round(_ratings[recipeId].Average(), 1);
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }

    public IReadOnlyList<Recipe> GetAllRecipes()
    {
        return _recipes.AsReadOnly();
    }
}

