@page "/"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="container">
    <div class="hero">
        <h1>🍳 Recipe Community</h1>
        <p class="lead">Discover and share delicious recipes from around the world</p>
    </div>

    <h2>Browse by Category</h2>
    <div class="category-grid">
        @foreach (var category in RecipeService.GetCategories())
        {
            <a href="/recipes/category/@category" class="category-card">
                <span class="category-icon">@GetCategoryIcon(category)</span>
                <h3>@category</h3>
                <p>@RecipeService.GetRecipesByCategory(category).Count recipe(s)</p>
            </a>
        }
    </div>

    <h2>Recent Recipes</h2>
    <div class="recipe-list">
        @foreach (var recipe in RecipeService.GetAllRecipes().TakeLast(3).Reverse())
        {
            <a href="/recipes/@recipe.Id" class="recipe-card">
                <h4>@recipe.Title</h4>
                <span class="badge">@recipe.Category</span>
                <span class="rating">⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
            </a>
        }
    </div>
</div>

@code {
    private string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍕",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🥡",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍽️"
    };
}

