@page "/recipes/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<div class="container">
    <h1>@GetCategoryIcon(CategoryName) @CategoryName Recipes</h1>
    <a href="/" class="back-link">← Back to Categories</a>

    @if (Recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="recipe-list">
            @foreach (var recipe in Recipes)
            {
                <a href="/recipes/@recipe.Id" class="recipe-card">
                    <h3>@recipe.Title</h3>
                    <span class="rating">⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                </a>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> Recipes { get; set; } = Array.Empty<Recipe>();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }

    private string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍕",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🥡",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍽️"
    };
}

@page "/recipes/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe Not Found")</PageTitle>

<div class="container">
    @if (Recipe == null)
    {
        <h1>Recipe Not Found</h1>
        <p>Sorry, we couldn't find that recipe.</p>
        <a href="/">← Back to Home</a>
    }
    else
    {
        <a href="/recipes/category/@Recipe.Category" class="back-link">← Back to @Recipe.Category</a>

        <h1>@Recipe.Title</h1>
        <span class="badge">@Recipe.Category</span>

        <section class="recipe-section">
            <h2>Ingredients</h2>
            <ul>
                @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                {
                    <li>@ingredient</li>
                }
            </ul>
        </section>

        <section class="recipe-section">
            <h2>Instructions</h2>
            @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step</p>
            }
        </section>

        <section class="recipe-section">
            <h2>Rating</h2>
            <p>⭐ @Recipe.AverageRating.ToString("F1") out of 5 (@Recipe.RatingCount ratings)</p>
            <RecipeCommunity.Components.Shared.StarRating RecipeId="Recipe.Id" />
        </section>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<div class="container">
    <h1>📝 Submit a Recipe</h1>
    <p>Share your favorite recipe with the community!</p>

    @if (Submitted)
    {
        <div class="success-message">
            <h3>✅ Recipe Submitted!</h3>
            <p>Thank you for sharing "<strong>@Submission.Title</strong>" with the community.</p>
            <a href="/">← Back to Home</a>
        </div>
    }
    else
    {
        <EditForm Model="Submission" OnValidSubmit="HandleSubmit" class="recipe-form">
            <div class="form-group">
                <label for="title">Recipe Title</label>
                <InputText id="title" @bind-Value="Submission.Title" placeholder="e.g., Grandma's Apple Pie" />
            </div>

            <div class="form-group">
                <label for="category">Category</label>
                <InputSelect id="category" @bind-Value="Submission.Category">
                    <option value="">-- Select a category --</option>
                    <option value="Italian">Italian</option>
                    <option value="Indian">Indian</option>
                    <option value="Mexican">Mexican</option>
                    <option value="Asian">Asian</option>
                    <option value="Desserts">Desserts</option>
                    <option value="Salads">Salads</option>
                    <option value="Other">Other</option>
                </InputSelect>
            </div>

            <div class="form-group">
                <label for="ingredients">Ingredients (comma-separated)</label>
                <InputTextArea id="ingredients" @bind-Value="Submission.Ingredients" rows="4"
                    placeholder="Flour, Sugar, Butter, Eggs, Apples, Cinnamon" />
            </div>

            <div class="form-group">
                <label for="steps">Steps (one per line)</label>
                <InputTextArea id="steps" @bind-Value="Submission.Steps" rows="6"
                    placeholder="1. Preheat oven to 350°F.&#10;2. Mix dry ingredients.&#10;3. ..." />
            </div>

            <button type="submit" class="btn-submit">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    private RecipeSubmission Submission { get; set; } = new();
    private bool Submitted { get; set; }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Submission.Title) || string.IsNullOrWhiteSpace(Submission.Category))
            return;

        RecipeService.SubmitRecipe(Submission);
        Submitted = true;
    }
}

