<div class="star-rating">
    @if (UserRating > 0)
    {
        <p class="rating-thanks">Thanks! You rated this @UserRating star(s).</p>
    }
    else
    {
        <p>Rate this recipe:</p>
        <div class="stars">
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <button class="star-btn @(HoverRating >= star ? "hovered" : "")"
                        @onclick="() => SubmitRating(star)"
                        @onmouseover="() => HoverRating = star"
                        @onmouseout="() => HoverRating = 0"
                        aria-label="Rate @star stars">
                    @(HoverRating >= star ? "★" : "☆")
                </button>
            }
        </div>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int UserRating { get; set; }
    private int HoverRating { get; set; }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        UserRating = stars;
    }
}

